#!/usr/bin/env bash
set -euo pipefail

# Thin host adapter. Pass a structured entry file generated by a Claude Code skill.

PROJECT="${QIJU_PROJECT:-$(basename "$PWD")}"
AGENT="${QIJU_AGENT:-claude}"
SOURCE="${1:-manual}"
BODY="${2:-}"

if [ -z "$BODY" ]; then
  echo "usage: claude_code.sh <manual|agent> <entry-json-file>" >&2
  exit 2
fi

exec qiju log --source "$SOURCE" --agent "$AGENT" --project "$PROJECT" --body "$BODY"
